+    result += `${link.isImage ? '!' : ''}[[${link.target}${display}]]`;
+    index = link.end;
+  }
+  return result;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  const isImage = text[start] === '!' && text[start + 1] === '[';
+  const labelStart = isImage ? start + 1 : start;
+  if (text[labelStart] !== '[') {
+    return null;
+  }
