+  let depth = 1;
+  let label = '';
+  while (index < text.length && depth > 0) {
+    const character = text[index];
+    if (character === '\
' || character === '\\r') return null;
+    if (character === '\\\' && index + 1 < text.length) {
+      label += text[index + 1];
+      index += 2;
+    } else if (character === '[') {
+      depth++;
+      label += character;
+      index++;
+    } else if (character === ']') {
+      depth--;
+      if (depth > 0) label += character;
+      index++;
+    } else {
+      label += character;
+      index++;
+    }
+  }
+  if (depth !== 0 || text[index] !== '(') return null;
+
+  const destinationStart = ++index;
+  let parentheses = 1;
+  let inAngleDestination = false;
+  while (index < text.length && parentheses > 0) {
+    const character = text[index];
+    if (character === '\
' || character === '\\r') return null;
+    if (character === '\\\' && index + 1 < text.length) {
+      index += 2;
+    } else if (character === '<' && parentheses === 1) {
+      inAngleDestination = true;
+      index++;
+    } else if (character === '>' && inAngleDestination) {
+      inAngleDestination = false;
+      index++;
+    } else if (character === '(' && !inAngleDestination) {
+      parentheses++;
+      index++;
+    } else if (character === ')' && !inAngleDestination) {
+      parentheses--;
+      index++;
+    } else {
+      index++;
+    }
+  }
+  if (parentheses !== 0) return null;
+
+  const target = parseDestination(text.substring(destinationStart, index - 1));
+  if (target === null) return null;
+  return {end: index, isImage, label, target};
+}
+
+function parseDestination(value: string): string | null {
+  const trimmed = value.trim();
+  if (trimmed === '') return null;
+
+  if (trimmed.startsWith('<')) {
+    if (!trimmed.endsWith('>')) return null;
+    return unescapeMarkdown(trimmed.substring(1, trimmed.length - 1));
+  }
+
+  // Whitespace outside an angle destination is a title (or unsupported syntax).
+  for (let index = 0; index < trimmed.length; index++) {
+    if (trimmed[index] === '\\\') {
+      index++;
+    } else if (/\\s/.test(trimmed[index])) {
